class WebSocketFrame {
  final bool finalFragment;
  final int opcode;
  final List<int> payload;

  WebSocketFrame({
    required this.finalFragment,
    required this.opcode,
    required Iterable<int> payload,
  }) : payload = List<int>.unmodifiable(payload) {
    if (opcode < 0 || opcode > 0x0f) {
      throw ArgumentError.value(opcode, 'opcode', 'must fit four bits');
    }
    if (isControl && (!finalFragment || this.payload.length > 125)) {
      throw ArgumentError('control frames must be final and at most 125 bytes');
    }
  }

  bool get isControl => opcode >= 0x08;
}

