import 'websocket_frame.dart';

class WebSocketDecoder {
  List<WebSocketFrame> add(List<int> bytes) {
    if (bytes.length < 2) {
      return const <WebSocketFrame>[];
    }

    final first = bytes[0];
    final second = bytes[1];
    if ((second & 0x80) != 0) {
      throw const FormatException('server frames must not be masked');
    }
    final length = second & 0x7f;
    if (length >= 126) {
      throw const FormatException('extended payloads are not supported');
    }
    if (bytes.length < 2 + length) {
      return const <WebSocketFrame>[];
    }

    return <WebSocketFrame>[
      WebSocketFrame(
        finalFragment: (first & 0x80) != 0,
        opcode: first & 0x0f,
        payload: bytes.sublist(2, 2 + length),
      ),
    ];
  }
}

