import 'dart:convert';

import 'websocket_frame.dart';

class WebSocketMessageAssembler {
  List<int>? _textPayload;

  List<String> add(WebSocketFrame frame) {
    if (frame.opcode == 0x01) {
      if (_textPayload != null) {
        throw StateError('a fragmented text message is already active');
      }
      if (frame.finalFragment) {
        return <String>[utf8.decode(frame.payload)];
      }
      _textPayload = <int>[...frame.payload];
      return const <String>[];
    }

    if (frame.opcode == 0x00) {
      final active = _textPayload;
      if (active == null) {
        throw StateError('continuation frame has no active message');
      }
      active.addAll(frame.payload);
      if (!frame.finalFragment) {
        return const <String>[];
      }
      _textPayload = null;
      return <String>[utf8.decode(active)];
    }

    _textPayload = null;
    return const <String>[];
  }
}

