import 'dart:convert';

import '../lib/websocket_decoder.dart';
import '../lib/websocket_messages.dart';

void check(bool condition, String message) {
  if (!condition) {
    throw StateError(message);
  }
}

void main() {
  final payload = utf8.encode('ready');
  final frames = WebSocketDecoder().add(<int>[
    0x81,
    payload.length,
    ...payload,
  ]);
  check(frames.length == 1, 'decodes one complete frame');
  check(frames.single.finalFragment, 'keeps the final-fragment flag');
  check(frames.single.opcode == 0x01, 'keeps the text opcode');

  final messages = WebSocketMessageAssembler().add(frames.single);
  check(
    messages.length == 1 && messages.single == 'ready',
    'emits a complete text message',
  );

  print('public tests passed');
}
